import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(-1);
    const [isPlaying, setIsPlaying] = useState(false);
    const audioRef = useRef(null);

    const currentSong = currentIndex !== -1 ? songs[currentIndex] : null;

    useEffect(() => {
        const fetchSongs = async () => {
            try {
                const res = await axios.get('http://localhost:5000/api/songs');
                setSongs(res.data);
            } catch (err) { console.error(err); }
        };
        fetchSongs();
    }, []);

    const playSong = (index) => {
        setCurrentIndex(index);
        setIsPlaying(true);
    };

    const nextSong = () => {
        const nextIndex = (currentIndex + 1) % songs.length;
        setCurrentIndex(nextIndex);
        setIsPlaying(true);
    };

    const prevSong = () => {
        const prevIndex = (currentIndex - 1 + songs.length) % songs.length;
        setCurrentIndex(prevIndex);
        setIsPlaying(true);
    };

    const togglePlay = () => {
        if (isPlaying) {
            audioRef.current.pause();
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    };

    return (
        <div style={{ padding: '20px', maxWidth: '1000px', margin: '0 auto', fontFamily: 'Arial', paddingBottom: '120px' }}>
            <h2 style={{ textAlign: 'center', marginBottom: '40px', fontSize: '28px', fontWeight: 'bold' }}>DANH SÁCH BÀI HÁT</h2>
            
            {/* PHẦN DANH SÁCH BÀI HÁT - FIX THEO ẢNH MẪU */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                {songs.map((song, index) => (
                    <div key={song._id} style={{
                        display: 'flex', 
                        alignItems: 'center', 
                        padding: '15px 30px', 
                        border: '1px solid #eee', 
                        borderRadius: '15px',
                        background: '#fff',
                        boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
                        justifyContent: 'space-between' // Đẩy nút Play về bên phải
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center', flex: 1 }}>
                            <img 
                                src={song.imageUrl ? `http://localhost:5000${song.imageUrl}` : 'https://via.placeholder.com/80'} 
                                style={{ width: '80px', height: '80px', marginRight: '25px', borderRadius: '10px', objectFit: 'cover' }} 
                                alt="cover"
                            />
                            <div style={{ textAlign: 'left' }}>
                                <div style={{ fontWeight: 'bold', fontSize: '20px', color: '#333' }}>{song.title}</div>
                                <div style={{ fontSize: '16px', color: '#888', marginTop: '5px' }}>{song.artist}</div>
                            </div>
                        </div>

                        <button 
                            onClick={() => playSong(index)} 
                            style={{ 
                                padding: '12px 35px', 
                                background: '#28a745', 
                                color: '#fff', 
                                border: 'none', 
                                borderRadius: '30px', 
                                cursor: 'pointer', 
                                fontWeight: 'bold',
                                fontSize: '16px',
                                width: 'auto' // Đảm bảo nút không bị giãn
                            }}
                        >
                            PLAY
                        </button>
                    </div>
                ))}
            </div>

            {/* THANH ĐIỀU KHIỂN NHẠC CỐ ĐỊNH */}
            {currentSong && (
                <div style={{
                    position: 'fixed', bottom: 0, left: 0, right: 0, 
                    background: '#181818', color: '#fff', padding: '15px 40px', 
                    display: 'flex', alignItems: 'center', justifyContent: 'space-between', zIndex: 1000,
                    boxShadow: '0 -5px 20px rgba(0,0,0,0.2)'
                }}>
                    {/* Trái: Thông tin */}
                    <div style={{ display: 'flex', alignItems: 'center', width: '30%' }}>
                        <img src={`http://localhost:5000${currentSong.imageUrl}`} style={{ width: '55px', height: '55px', borderRadius: '5px', marginRight: '15px' }} alt="mini-cover" />
                        <div style={{ textAlign: 'left', overflow: 'hidden' }}>
                            <div style={{ fontWeight: 'bold', fontSize: '15px', whiteSpace: 'nowrap', textOverflow: 'ellipsis' }}>{currentSong.title}</div>
                            <div style={{ fontSize: '13px', color: '#b3b3b3' }}>{currentSong.artist}</div>
                        </div>
                    </div>

                    {/* Giữa: Nút điều khiển */}
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: '40%' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '30px' }}>
                            <button onClick={prevSong} style={btnIconStyle}>⏮</button>
                            <button onClick={togglePlay} style={btnMainPlayStyle}>
                                {isPlaying ? '⏸' : '▶'}
                            </button>
                            <button onClick={nextSong} style={btnIconStyle}>⏭</button>
                        </div>
                        <audio 
                            ref={audioRef}
                            src={`http://localhost:5000${currentSong.songUrl}`} 
                            autoPlay 
                            onEnded={nextSong}
                            onPlay={() => setIsPlaying(true)}
                            onPause={() => setIsPlaying(false)}
                        />
                    </div>

                    {/* Phải: Trống để cân bằng */}
                    <div style={{ width: '30%' }}></div>
                </div>
            )}
        </div>
    );
};

const btnIconStyle = { background: 'none', border: 'none', color: '#fff', fontSize: '28px', cursor: 'pointer' };
const btnMainPlayStyle = {
    background: '#fff', border: 'none', color: '#000', width: '45px', height: '45px', 
    borderRadius: '50%', fontSize: '20px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center'
};

export default Home;
